import moment from 'moment';
import { LEVEL } from './Const';

export const getMessages = messagesFromBo => {
    if (messagesFromBo && Array.isArray(messagesFromBo)) {
        return messagesFromBo.map(msg => getMessage(msg));
    }
    return [];
};

export const getMessage = messageFromApi => {
    return {
        id: messageFromApi.Id,
        conversationId: messageFromApi.ConversationId,
        isRead: messageFromApi.IsRead,
        messageText: messageFromApi.Message,
        timeStamp: `${messageFromApi.CreateDateText}  ${messageFromApi.CreateTimeText}`,
        user: getUser(messageFromApi.Sender, messageFromApi.SenderName)
    };
};

export const getUsers = usersFromApi => {
    if (usersFromApi && Array.isArray(usersFromApi)) {
        return usersFromApi.map(user => getUser(user));
    }
    return [];
};

export const getUser = (userFromApi, userDisplayName /*optional*/) => {
    return {
        id: userFromApi.Id,
        name: userDisplayName
            ? userDisplayName
            : userFromApi.DisplayName
            ? userFromApi.DisplayName
            : `${userFromApi.GivenName} ${userFromApi.FamilyName}`,
        isAnonymous: userFromApi.IsAnonymous,
        isReporter: userFromApi.IsReporter
    };
};

export const getConversations = conversationsFromApi => {
    if (conversationsFromApi && Array.isArray(conversationsFromApi)) {
        return conversationsFromApi.map(conv => getConversation(conv));
    }
    return [];
};

export const getConversation = conversationFromApi => {
    const messages = getMessages(conversationFromApi.ConversationMessages);
    const users = getUsers(conversationFromApi.Users);
    return {
        id: conversationFromApi.Id,
        users,
        messages,
        level: getLevel(conversationFromApi.RelateClass),
        relateId: conversationFromApi.RelateId,
        lastUpdateTime: moment().calendar(conversationFromApi.UpdateDate)
    };
};

const getLevel = ApiClassName => {
    if (ApiClassName.indexOf('Incident') >= 0) {
        return LEVEL.CASE;
    } else if (ApiClassName.indexOf('WorkItemTask') >= 0) {
        return LEVEL.TASK;
    }
    throw error(`Cannot derive level from ${ApiClassName}`);
};

export const resolveIncidents = incidentsFromApi => {
    if (incidentsFromApi && Array.isArray(incidentsFromApi)) {
        return incidentsFromApi.map(inc => resolveIncident(inc));
    }
    return [];
};

export const resolveIncident = incidentFromApi => {
    const conversations = getConversations(incidentFromApi.Conversations);
    return {
        id: incidentFromApi.IncidentId.toString(),
        incidentNumber: incidentFromApi.IncidentNumber,
        workItemId: incidentFromApi.WorkItemId,
        category: incidentFromApi.Category,
        subCategory: incidentFromApi.SubCategory,
        status: incidentFromApi.Status,
        dueDate: moment(incidentFromApi.DueDate).format('L'),
        reported: moment(incidentFromApi.Reported).format('L'),
        taskList: getTaskConversationList(incidentFromApi.TaskConversationList),
        conversations: conversations
    };
};

export const getTaskConversationList = taskConvListFromApi => {
    if (taskConvListFromApi && Array.isArray(taskConvListFromApi)) {
        return taskConvListFromApi.map(taskConv => getTaskConversation(taskConv));
    }
    return [];
};

export const getTaskConversation = taskConversationFromApi => {
    const conversations = getConversations(taskConversationFromApi.Conversations);
    return {
        id: taskConversationFromApi.TaskId.toString(),
        incidentId: taskConversationFromApi.IncidentId.toString(),
        name: taskConversationFromApi.Name,
        description: taskConversationFromApi.Description,
        conversations: conversations
    };
};
