import React from 'react';

const Select = props => {
    const { options, name, className, value, style, isDisabled, isReadOnly, handleChange } = props;
    return (
        <select
            name={name}
            value={value}
            onChange={handleChange}
            style={style}
            className={className}
            disabled={isDisabled}
            readOnly={isReadOnly}
        >
            {options && Array.isArray(options) ? (
                options.map((opt, index) => {
                    return (
                        <option value={opt.value} key={index}>
                            {opt.label}
                        </option>
                    );
                })
            ) : (
                <option value={null}>-- Select --</option>
            )}
        </select>
    );
};

export default Select;
