import { fetchData } from './Utilities';
import { logError } from './FilterActions';
import {
    SET_CURRENT_USER,
    FINISH_SEND_MESSAGE,
    ERROR_SEND_MESSAGE,
    LAUNCH_CONTACT_MODAL,
    CLOSE_MODAL,
    SELECT_CONVERSATION,
    SELECT_INCIDENT,
    SELECT_TASK,
    CHANGE_CONTEXT,
    AUTO_SAVE_UNSEND_MESSAGE,
    FETCH_CONVERSATION_LIST,
    FETCH_CONTACT_LIST,
    FETCH_INCIDENT_LIST,
    END_FETCH_INCIDENTS,
    LOADING,
    FINISH_CREATE_CONVERSATION,
    FINISH_ADD_USER_TO_CONVERSATION,
    ERROR_CREATE_CONVERSATION,
    MARK_ALL_MESSAGES_READ,
    START_FETCH_CONVERSATION,
    START_FETCH_INCIDENT,
    LEVEL
} from '../Helpers/Const';
import { getUsers, getConversations, getConversation, resolveIncidents } from './IntraSystemMessageHelper';

const baseUrl = location.href.substring(0, location.href.lastIndexOf('/Messaging'))
    ? location.href.substring(0, location.href.lastIndexOf('/Messaging'))
    : location.href.substring(0, location.href.lastIndexOf('/IncidentReport'));

//Pure functions
export const launchContactModal = conversationId => {
    return { type: LAUNCH_CONTACT_MODAL, payload: { conversationId } };
};

export const closeModal = () => {
    return { type: CLOSE_MODAL };
};

export const setCurrentUser = id => {
    return { type: SET_CURRENT_USER, payload: { id } };
};

export const autoSaveUnsendMessage = unsendMessage => {
    return { type: AUTO_SAVE_UNSEND_MESSAGE, payload: { unsendMessage } };
};

export const selectConversation = conversationId => {
    return { type: SELECT_CONVERSATION, payload: { conversationId } };
};

export const selectTask = taskId => {
    return { type: SELECT_TASK, payload: { taskId } };
};

export const selectIncident = (incidentId, workItemId) => {
    return { type: SELECT_INCIDENT, payload: { incidentId, workItemId } };
};

export const changeContext = context => ({
    type: CHANGE_CONTEXT,
    payload: { context }
});

export const startAsyncFunction = type => {
    let actionType = '';
    switch (type) {
        case FETCH_INCIDENT_LIST:
            actionType = START_FETCH_INCIDENT;
            break;
        case FETCH_CONVERSATION_LIST:
            actionType = START_FETCH_CONVERSATION;
            break;
        //Add more later...
        default:
            actionType = LOADING;
            break;
    }
    return { type: actionType };
};

export const fetchConversationList = conversations => {
    return {
        type: FETCH_CONVERSATION_LIST,
        payload: { conversations }
    };
};

export const fetchContactList = (allUsers, currentUserId) => {
    return {
        type: FETCH_CONTACT_LIST,
        payload: { allUsers, currentUserId }
    };
};

export const fetchIncidentList = (incidents, currentIncidentId, hasNewMessage) => {
    return {
        type: END_FETCH_INCIDENTS,
        payload: { incidents, currentIncidentId, hasNewMessage }
    };
};

export const markAllMessagesRead = conversation => {
    return {
        type: MARK_ALL_MESSAGES_READ,
        payload: { conversation }
    };
};

export const initializeMessage = conversation => {
    return {
        type: FINISH_SEND_MESSAGE,
        payload: { conversation }
    };
};

export const initializeConversation = conversation => {
    return {
        type: FINISH_CREATE_CONVERSATION,
        payload: { conversation }
    };
};

export const addUserToConversation = conversation => {
    return {
        type: FINISH_ADD_USER_TO_CONVERSATION,
        payload: { conversation }
    };
};

//Async functions
export const markAllMessagesReadThunk = (endpoint, conversationId, incidentId) => {
    return dispatch => {
        return fetchData(baseUrl + endpoint, JSON.stringify({ conversationId, incidentId })).then(
            result => {
                const conversation = getConversation(result.conversation);
                dispatch(markAllMessagesRead(conversation));
            },
            error => dispatch(logError(error))
        );
    };
};

export const fetchConversationListThunk = (endpoint, incidentNumber) => {
    return dispatch => {
        return fetchData(baseUrl + endpoint, JSON.stringify({ incidentNumber })).then(
            result => {
                const conversations = getConversations(result.conversations);
                dispatch(fetchConversationList(conversations));
            },
            error => dispatch(logError(error))
        );
    };
};

export const fetchContactListThunk = (endpoint, incidentIdOrNumber, isSubmitterMode, callback) => {
    return dispatch => {
        return fetchData(baseUrl + endpoint, JSON.stringify({ incidentIdOrNumber, isSubmitterMode }))
            .then(
                result => {
                    const { currentUserId, users, incidentId } = result;
                    const allUsers = getUsers(users);
                    dispatch(fetchContactList(allUsers, currentUserId.toString()));
                    return incidentId;
                },
                error => dispatch(logError(error))
            )
            .then(incidentId => {
                if (callback && typeof callback == 'function') {
                    dispatch(callback(incidentId));
                }
            });
    };
};

export const fetchIncidentListThunk = (
    endpoint,
    currentWorkItemId,
    currentIncidentNumber,
    keepCurrentState,
    { taskId, type },
    fromAutoSync
) => {
    return dispatch => {
        return fetchData(
            baseUrl + endpoint,
            JSON.stringify({ incidentNumber: currentIncidentNumber, workItemId: currentWorkItemId, fromAutoSync })
        )
            .then(
                result => {
                    const resolvedIncidents = resolveIncidents(result.incidents);
                    dispatch(fetchIncidentList(resolvedIncidents, result.incidentId, result.hasNewMessage));
                    return { incidentId: result.incidentId, workItemId: result.workItemId };
                },
                error => dispatch(logError(error))
            )
            .then(({ incidentId, workItemId }) => {
                if (!keepCurrentState) {
                    dispatch(selectIncident(incidentId, workItemId));
                }
            })
            .then(() => {
                if (!keepCurrentState) {
                    if (type == LEVEL.TASK && parseInt(taskId) > 0) {
                        dispatch(selectTask(taskId));
                    }
                }
            });
    };
};

export const initializeMessageThunk = (endpoint, message, conversationId, workItemId) => {
    return dispatch => {
        return fetchData(baseUrl + endpoint, JSON.stringify({ message, conversationId, workItemId })).then(
            result => {
                dispatch(initializeMessage(getConversation(result.conversation)));
            },
            error => dispatch({ type: ERROR_SEND_MESSAGE, payload: { error } })
        );
    };
};

export const initializeConversationThunk = (endpoint, userIdList, incidentId, taskId, workItemId, mode) => {
    return dispatch => {
        return fetchData(
            baseUrl + endpoint,
            JSON.stringify({
                userIds: userIdList.join(','),
                incidentId,
                taskId,
                workItemId,
                mode
            })
        ).then(
            result => {
                dispatch(initializeConversation(getConversation(result.conversation)));
            },
            error => dispatch({ type: ERROR_CREATE_CONVERSATION, payload: { error } })
        );
    };
};

export const addUserToConversationThunk = (endpoint, userIdList, conversationId, incidentId) => {
    return dispatch => {
        return fetchData(
            baseUrl + endpoint,
            JSON.stringify({
                userIds: userIdList.join(','),
                conversationId,
                incidentId
            })
        ).then(
            result => {
                dispatch(addUserToConversation(getConversation(result.conversation)));
            },
            error => dispatch({ type: ERROR_CREATE_CONVERSATION, payload: { error } })
        );
    };
};
