/**
 * Design Tokens Utility
 *
 * Provides easy access to Atlas Lens design tokens.
 * Import this file instead of directly importing from @diligentcorp/atlas-design-tokens/lens
 * to ensure consistent usage across the application.
 */
 
import { semantic, core, component } from '@diligentcorp/atlas-design-tokens/lens';
 
/**
 * Helper function to get token value
 * @param {object} token - Token object with value property
 * @returns {string} - The token value (e.g., color hex code)
 */
const getValue = (token) => token?.value || token;
 
/**
 * Semantic Color Tokens
 * Use semantic tokens for UI elements as they provide context-aware colors
 */
export const colors = {
  // Action colors
  action: {
    primary: {
      default: getValue(semantic?.color?.action?.primary?.default),
      hover: getValue(semantic?.color?.action?.primary?.hover),
      active: getValue(semantic?.color?.action?.primary?.active),
      disabled: getValue(semantic?.color?.action?.primary?.disabled),
      onPrimary: getValue(semantic?.color?.action?.primary?.onPrimary),
    },
    secondary: {
      outline: getValue(semantic?.color?.action?.secondary?.outline),
      hoverFill: getValue(semantic?.color?.action?.secondary?.hoverFill),
      activeFill: getValue(semantic?.color?.action?.secondary?.activeFill),
      disabledOutline: getValue(semantic?.color?.action?.secondary?.disabledOutline),
      onSecondary: getValue(semantic?.color?.action?.secondary?.onSecondary),
    },
    destructive: {
      default: getValue(semantic?.color?.action?.destructive?.default),
      hover: getValue(semantic?.color?.action?.destructive?.hover),
      active: getValue(semantic?.color?.action?.destructive?.active),
      disabled: getValue(semantic?.color?.action?.destructive?.disabled),
      onDestructive: getValue(semantic?.color?.action?.destructive?.onDestructive),
    },
    link: {
      default: getValue(semantic?.color?.action?.link?.default),
      hover: getValue(semantic?.color?.action?.link?.hover),
      active: getValue(semantic?.color?.action?.link?.active),
      disabled: getValue(semantic?.color?.action?.link?.disabled),
    },
  },

  // Type colors (text colors)
  type: {
    default: getValue(semantic?.color?.type?.default),
    secondary: getValue(semantic?.color?.type?.secondary),
    tertiary: getValue(semantic?.color?.type?.tertiary),
    disabled: getValue(semantic?.color?.type?.disabled),
    inverse: getValue(semantic?.color?.type?.inverse),
    link: getValue(semantic?.color?.type?.link),
    linkHover: getValue(semantic?.color?.type?.linkHover),
  },

  // Background colors
  background: {
    default: getValue(semantic?.color?.background?.default),
    secondary: getValue(semantic?.color?.background?.secondary),
    tertiary: getValue(semantic?.color?.background?.tertiary),
    inverse: getValue(semantic?.color?.background?.inverse),
    overlay: getValue(semantic?.color?.background?.overlay),
    selected: getValue(semantic?.color?.background?.selected) || getValue(core?.color?.gray?.['100']), // Selected menu item background
  },

  // UI element colors
  ui: {
    border: {
      default: getValue(semantic?.color?.ui?.border?.default),
      static: getValue(semantic?.color?.ui?.border?.static),
      interactive: getValue(semantic?.color?.ui?.border?.interactive),
      focus: getValue(semantic?.color?.ui?.border?.focus),
      error: getValue(semantic?.color?.ui?.border?.error),
    },
    divider: getValue(semantic?.color?.ui?.divider),
  },

  // Status colors
  status: {
    success: getValue(semantic?.color?.status?.success?.default) || getValue(semantic?.color?.status?.success) || '#8ee400',
    warning: getValue(semantic?.color?.status?.warning?.default) || getValue(semantic?.color?.status?.warning) || '#fee400',
    error: getValue(semantic?.color?.status?.error?.default) || getValue(semantic?.color?.status?.error) || '#921a1d',
    info: getValue(semantic?.color?.status?.info?.default) || getValue(semantic?.color?.status?.info) || '#1976d2',
  },
};
 
/**
 * Core Color Tokens
 * Use core tokens only when semantic tokens don't provide the needed color
 */
export const coreColors = {
  gray: Object.keys(core?.color?.gray || {}).reduce((acc, key) => {
    acc[key] = getValue(core?.color?.gray?.[key]);
    return acc;
  }, {}),
  brand: Object.keys(core?.color?.brand || {}).reduce((acc, key) => {
    acc[key] = getValue(core?.color?.brand?.[key]);
    return acc;
  }, {}),
  red: Object.keys(core?.color?.red || {}).reduce((acc, key) => {
    acc[key] = getValue(core?.color?.red?.[key]);
    return acc;
  }, {}),
  // Add other core colors as needed
};
 
/**
 * Common color mappings for frequently used hardcoded colors
 * This helps with migration from hardcoded values
 *
 * NOTE: Different color codes should map to different design tokens when they represent
 * different visual shades. Use core color tokens (coreColors.gray.*) when semantic tokens
 * don't provide an exact match.
 */
export const colorMappings = {
  // Common grays - Text colors
  '#282e37': colors.type.default, // Dark text (matches Core.Color.Gray.900 = #282e37)
  '#1a1d23': coreColors.gray['950'], // Darker variant (closest to Core.Color.Gray.950 = #121a26)
  '#666666': coreColors.gray['600'], // Medium gray text (closest to Core.Color.Gray.600 = #8c8e92)
  '#6f7377': colors.type.secondary, // Medium gray text (matches Core.Color.Gray.700 = #6f7377)
  '#999': colors.type.disabled, // Light gray text (closest to Core.Color.Gray.500 = #a0a2a5)
  '#999999': colors.type.disabled, // Light gray text (full hex, same as above)
 
  // Border colors - Use semantic token for exact match, core tokens for variants
  '#dadada': colors.ui.border.static, // Light border (matches Core.Color.Gray.300 = #dadada)
  '#e0e0e0': coreColors.gray['200'], // Light border variant (closest to Core.Color.Gray.200 = #e6e6e6)
  '#ddd': coreColors.gray['200'], // Very light border (closest to Core.Color.Gray.200 = #e6e6e6)
  '#ccc': coreColors.gray['400'], // Very light border variant (closest to Core.Color.Gray.400 = #b6b8b9)
 
  // Background colors
  '#f5f5f5': coreColors.gray['100'], // Light background (closest to Core.Color.Gray.100 = #f3f3f3)
  '#f9f9f9': colors.background.tertiary, // Very light background
  '#f0f0f0': colors.action.secondary.hoverFill, // Hover background (matches Core.Color.Gray.100 = #f3f3f3)
  '#ffffff': colors.background.default, // White (matches Core.Color.Gray.0 = #ffffff)
  '#f3f3f3': colors.background.selected, // Selected menu item background
  '#fbfbfb': coreColors.gray['100'], // Off-white background (closest to Core.Color.Gray.100 = #f3f3f3)
 
  // Status colors - Note: These hardcoded values don't match exact token values but are mapped to closest semantic tokens
  '#d32f2f': colors.status.error,
   // Error red (closest to Core.Color.Brand.Primary.Red 4 = #921a1d)
  '#ed6c02': colors.status.warning, // Warning orange (closest to Core.Color.Yellow.90 = #fee400)
  '#2e7d32': colors.status.success, // Success green (closest to Core.Color.Green.90 = #8ee400)
  '#1976d2': colors.action.link.default, // Info blue (closest to Core.Color.Brand.Primary.Red 2 = #d3222a)
  '#1565c0': colors.action.link.active,

  '#8EE400': colors.status.success.toast,
  '#ed6c02': colors.status.warning.toast,
  '#1976d2': colors.status.info,
  '#d32f2f': colors.status.error.toast,

  
  // Darker blue (closest to Core.Color.Brand.Primary.Red 4 = #921a1d)
 
  // Error backgrounds
  '#ffebee': coreColors.red['95'] || coreColors.gray['100'], // Light error background (matches Core.Color.Red.95 = #ffedeb)
};
 
/**
 * Sets CSS custom properties (CSS variables) on the document root
 * This allows CSS files to use design tokens via var(--color-*)
 * Call this function once when the application initializes
 */
export const setDesignTokenCSSVariables = () => {
  if (typeof document === 'undefined') return; // Server-side rendering check
  
  const root = document.documentElement;
  
  // Helper function to convert nested object to CSS variables
  const setCSSVars = (obj, prefix = '--color') => {
    Object.keys(obj).forEach(key => {
      const value = obj[key];
      const varName = `${prefix}-${key}`;
      
      if (typeof value === 'object' && value !== null && !Array.isArray(value)) {
        // Recursively process nested objects
        setCSSVars(value, varName);
      } else if (value !== undefined && value !== null) {
        // Set the CSS variable
        root.style.setProperty(varName, value);
      }
    });
  };
  
  // Set CSS variables from colors object
  setCSSVars(colors);
  
  // Set commonly used flattened variables for easier access in CSS
  root.style.setProperty('--color-background-default', colors.background.default);
  root.style.setProperty('--color-background-secondary', colors.background.secondary);
  root.style.setProperty('--color-background-tertiary', colors.background.tertiary);
  root.style.setProperty('--color-type-default', colors.type.default);
  root.style.setProperty('--color-type-secondary', colors.type.secondary);
  root.style.setProperty('--color-type-tertiary', colors.type.tertiary);
  root.style.setProperty('--color-action-link-default', colors.action.link.default);
  root.style.setProperty('--color-action-link-hover', colors.action.link.hover);
  root.style.setProperty('--color-action-link-active', colors.action.link.active);
  root.style.setProperty('--color-status-error', colors.status.error);
  root.style.setProperty('--color-status-success', colors.status.success);
  root.style.setProperty('--color-status-warning', colors.status.warning);
  root.style.setProperty('--color-status-info', colors.status.info);
  root.style.setProperty('--color-ui-border-static', colors.ui.border.static);
  root.style.setProperty('--color-ui-border-default', colors.ui.border.default);
  root.style.setProperty('--color-ui-border-error', colors.ui.border.error);
};

// Auto-initialize CSS variables if in browser environment
if (typeof window !== 'undefined' && typeof document !== 'undefined') {
  // Initialize on DOM ready
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', setDesignTokenCSSVariables);
  } else {
    setDesignTokenCSSVariables();
  }
}

// Export the raw token objects for advanced usage
export { semantic, core, component };