import React from "react";
import ConversationListItem from "./ConversationListItem";
import { Icon } from "react-icons-kit";
import { loader } from "react-icons-kit/feather/loader";

const ConversationList = props => {
  const {
    conversations,
    currentConversationId,
    selectConversation,
    firstPerspectiveId,
    isFetchingConversations
  } = props;
  const loaderWrapperStyle = {
    display: "flex",
    flexDirection: "column",
    justifyContent: "center",
    alignItems: "center",
    padding: "20px"
  };
  const loaderStyle = {
    color: "#aaa",
    marginBotton: "10px"
  };
  let list;
  if (isFetchingConversations && (!conversations || conversations.length == 0)) {
    list = (
      <div style={loaderWrapperStyle}>
        <div style={loaderStyle}>
          <Icon size={36} icon={loader} />
        </div>
        <div>Loading conversations...</div>
      </div>
    );
  } else {
    if (conversations && conversations.length > 0) {
      list = conversations.map(cvs => (
        <ConversationListItem
          key={cvs.id}
          isCurrent={cvs.id == currentConversationId}
          handleClick={selectConversation}
          firstPerspectiveId={firstPerspectiveId}
          unreadCount={cvs.messages.filter(msg => !msg.isRead && msg.user.id.toString() !== firstPerspectiveId).length}
          {...cvs}
        />
      ));
    } else {
      list = <div style={{ padding: "10px", textAlign: "center" }}>Click Chat with to start</div>;
    }
  }

  return <ul className="list-group">{list}</ul>;
};

export default ConversationList;
