import React from 'react';
import { LEVEL } from '../../Helpers/Const';
import Select from '../Base/Select';

const ContextSwitcher = props => {
	const { level, tasks, selectTask, changeContext } = props;
	const selectStyle = { display: 'inline-block', marginLeft: '15px' };
	const containerStyle = { margin: '5px 0 15px 0' };
	const defaultOption = { label: '-- SELECT --', value: 0 };
	const options = tasks.map(t => ({
		value: t.id,
		label: t.name
	}));

	let currentTaskId = props.currentTaskId || 0;

	options.push(defaultOption);
	return (
		<div style={containerStyle}>
			<label className="radio-inline">
				<input
					type="radio"
					name="level"
					value={LEVEL.CASE}
					checked={level === LEVEL.CASE}
					onChange={e => changeContext(e.target.value)}
				/>
				Workflow Level
			</label>
			<label className="radio-inline">
				<input
					type="radio"
					name="level"
					value={LEVEL.TASK}
					checked={level === LEVEL.TASK}
					onChange={e => changeContext(e.target.value)}
				/>
				Task Level
			</label>
			{level === LEVEL.CASE ? (
				''
			) : (
				<Select
					name="task"
					options={options}
					className="form-control"
					value={currentTaskId}
					handleChange={e => selectTask(e.target.value)}
					isDisabled={false}
					style={selectStyle}
				/>
			)}
		</div>
	);
};

export default ContextSwitcher;
