import React from 'react';
import Spinner from 'react-spinkit';
import { colors } from '../../utils/designTokens';

const SpinnerPlaceholder = props => {
    const { height, width, color, type, background } = props;
    const style = {
        height: height || '100%',
        width: width || '100%',
        display: 'flex',
        justifyContent: 'center',
        alignItems: 'center',
        background: background || colors.background.secondary || '#eee'
    };
    const spinnerType = type || 'ball-clip-rotate';
    const spinnerColor = color || 'orange';
    return (
        <div style={style}>
            <Spinner name={spinnerType} color={spinnerColor} fadeIn="none" />
        </div>
    );
};

export default SpinnerPlaceholder;
