import React, { Component } from 'react';
import { LEVEL, ISM_MODE } from '../../Helpers/Const';

class ContactList extends Component {
    constructor(props) {
        super(props);
        this.state = {
            selectedUsers: []
        };
        this.select = this.select.bind(this);
        this.handleSave = this.handleSave.bind(this);
    }

    select(id) {
        let users = this.state.selectedUsers.slice();
        if (users.indexOf(id) >= 0) {
            users.splice(users.indexOf(id), 1);
        } else {
            users.push(id);
        }
        this.setState((prevState, state) => {
            return { selectedUsers: users };
        });
    }

    handleSave(selectedUsers, props, isStartNew) {
        const {
            initializeConversation,
            addUserToConversation,
            isSubmitterMode,
            currentTaskId,
            currentIncidentId,
            currentIncidentNumber,
            currentConversationId,
            currentWorkItemId,
            level
        } = props;

        if (isSubmitterMode) {
            initializeConversation(selectedUsers, currentIncidentNumber, null, currentWorkItemId, ISM_MODE.SUBMITTER);
        } else {
            if (!isStartNew) {
                addUserToConversation(selectedUsers, currentConversationId, currentIncidentId, ISM_MODE.INVESTIGATOR);
            } else {
                if (level === LEVEL.CASE) {
                    initializeConversation(
                        selectedUsers,
                        currentIncidentId,
                        null,
                        currentWorkItemId,
                        ISM_MODE.INVESTIGATOR
                    );
                } else {
                    initializeConversation(
                        selectedUsers,
                        currentIncidentId,
                        currentTaskId,
                        currentWorkItemId,
                        ISM_MODE.INVESTIGATOR
                    );
                }
            }
        }
    }

    render() {
        const { contacts, collapseList, isSubmitterMode, isStartNew, firstPerspectiveId } = this.props;

        let pillsList = <div>No associate is available to talk</div>;
        const pillStyle = {
            marginRight: '5px',
            marginBottom: '5px',
            borderRadius: '15px',
            display: 'inline-flex'
        };
        const buttonGroupStyle = {
            display: 'flex',
            marginTop: '20px',
            flexDirection: 'row-reverse'
        };
        const panelStyle = {
            padding: '10px',
            background: '#e3e3e3'
        };
        const confirmButtonClass = `btn btn-sm ${isStartNew ? 'btn-primary' : 'btn-success'}`;
        if (contacts && contacts.length > 0) {
            pillsList = contacts
                .filter(c => c.id != firstPerspectiveId)
                .map(c => {
                    const selected = this.state.selectedUsers.indexOf(c.id) >= 0;
                    const className = selected ? 'btn btn-sm btn-primary' : 'btn btn-sm btn-default';
                    return (
                        <button key={c.id} className={className} style={pillStyle} onClick={() => this.select(c.id)}>
                            {c.isReporter
                                ? c.isAnonymous
                                    ? `Anonymous (Reporter of ${c.name})`
                                    : `${c.name}(Reporter)`
                                : c.name}
                        </button>
                    );
                });
        }
        return (
            <div style={panelStyle}>
                {pillsList}
                <div style={buttonGroupStyle}>
                    <button className="btn btn-default btn-sm" onClick={collapseList}>
                        Cancel
                    </button>
                    <button
                        className={confirmButtonClass}
                        style={{ marginRight: '5px' }}
                        onClick={() => this.handleSave(this.state.selectedUsers, this.props, isStartNew)}
                    >
                        {isStartNew ? 'Start Chat' : 'Add to chat'}
                    </button>
                </div>
            </div>
        );
    }
}

export default ContactList;
