import { ISM_MODE } from '../Helpers/Const';
import initializeMessaging from '../Components/IntraSystemMessage/ISMRoot';

const intraSystemMessageInvestigator = document.getElementById('intra-sys-message-investigator');

//intra-system message (investigator)
if (intraSystemMessageInvestigator) {
    const incidentNumber = intraSystemMessageInvestigator.dataset.id;
    const taskId = intraSystemMessageInvestigator.dataset.taskId;
    const workItemId = intraSystemMessageInvestigator.dataset.wi;
    const type = intraSystemMessageInvestigator.dataset.type;
    const baseUrl = intraSystemMessageInvestigator.dataset.baseUrl;

    initializeMessaging(
        ISM_MODE.INVESTIGATOR,
        'intra-sys-message-investigator',
        type,
        incidentNumber,
        workItemId,
        taskId
    );
}
