import React, { Component, Fragment } from 'react';
import { scroller } from 'react-scroll';
import Message from './Message';
import InputBox from './InputBox';
import { isEqual } from '../../Helpers/Utilities';

class Conversation extends Component {
    constructor(props) {
        super(props);
        this.state = { messages: [], conversationId: '' };
        this.messageList = React.createRef();
    }

    componentDidMount() {
        const { markAllMessagesRead, conversation, firstPerspectiveId, currentIncidentId } = this.props;
        if (conversation.messages.filter(msg => !msg.isRead && msg.id.toString() !== firstPerspectiveId).length > 0) {
            markAllMessagesRead(conversation.id, currentIncidentId);
        }
        this.setState({
            messeges: conversation.messages,
            conversationId: conversation.id
        });
        this.scrollToWithContainer();
    }

    componentDidUpdate() {
        this.scrollToWithContainer();
    }

    shouldComponentUpdate(nextProps, nextState) {
        if (this.state.conversationId !== nextProps.conversation.id) {
            return true;
        }
        return !isEqual(nextProps.conversation.messages, this.state.messages);
    }

    scrollToWithContainer() {
        scroller.scrollTo('scroll-anchor', {
            duration: 800,
            delay: 0,
            smooth: 'easeInOutQuart',
            containerId: 'msg-list'
        });
    }

    render() {
        const { conversation, firstPerspectiveId, sendMessage, autoSaveUnsendMessage, currentWorkItemId } = this.props;
        const listWrapperStyle = {
            padding: '10px',
            background: '#fff',
            height: '320px',
            overflowY: 'scroll'
        };

        let messageList = [];
        let unsendMessage = '';

        if (conversation && conversation.messages) {
            const temp = conversation.messages.filter(msg => msg.isUnsend);
            if (temp.length == 1) {
                unsendMessage = temp[0];
            }
            //expect already being sorted by udpated time
            messageList = conversation.messages
                .filter(msg => !msg.isUnsend)
                .map(msg => (
                    <Message
                        key={msg.id}
                        message={msg}
                        firstPerspectiveId={firstPerspectiveId}
                        context={conversation.context}
                    />
                ));
        }

        return (
            <Fragment>
                <div style={listWrapperStyle} id="msg-list" ref={this.messageList}>
                    {messageList}
                    <span id="scroll-anchor" />
                </div>
                <InputBox
                    message={unsendMessage}
                    sendMessage={text => sendMessage(text, conversation.id, currentWorkItemId)}
                    autoSaveUnsendMessage={autoSaveUnsendMessage}
                />
            </Fragment>
        );
    }
}

export default Conversation;
