import React, { Component } from 'react';
import { Icon } from 'react-icons-kit';
import { send } from 'react-icons-kit/feather/send';

class InputBox extends Component {
	constructor(props) {
		super(props);
		this.state = {
			message: ''
		};
		this.handleChange = this.handleChange.bind(this);
		this.handleSend = this.handleSend.bind(this);
	}

	componentDidMount() {
		if (this.props.unsendMessage) {
			const unsendMessage = this.props.unsendMessage.trim();
			if (unsendMessage && unsendMessage.length > 0) {
				this.setState((preState, state) => {
					return { message: unsendMessage };
				});
			}
		}
	}

	handleChange(event) {
		this.setState({ message: event.target.value });
	}

	handleSend(msg) {
		if (msg && msg.length > 0 && msg.trim().length > 0) {
			this.resetState();
			this.props.sendMessage(msg);
		}
	}

	resetState() {
		this.setState({ message: '' });
	}

	render() {
		const { autoSaveUnsendMessage } = this.props;
		const { message } = this.state;
		const buttonStyle = {
			position: 'absolute',
			right: '16px',
			top: '20px',
			color: '#DBEBF9'
		};
		const textAreaStyle = {
			paddingRight: '80px',
			borderRadius: '0px',
			border: '1px solid #eee',
			boxShadow: 'none'
		};
		return (
			<div style={{ position: 'relative' }}>
				<textarea
					value={message}
					onChange={this.handleChange}
					onBlur={() => {
						autoSaveUnsendMessage(message);
					}}
					className="form-control"
					style={textAreaStyle}
					rows="3"
				/>
				<div
					className="sendIcon"
					style={buttonStyle}
					onClick={() => {
						this.handleSend(message);
					}}
				>
					<Icon size={36} icon={send} />
				</div>
			</div>
		);
	}
}

export default InputBox;
