export const getBadgeIcon = (valueTypeText) =>{
	switch(valueTypeText){
		case 'Text':
			return <TextIcon />
		case 'Date':
			return <CalendarIcon />
		case 'Number':
			return <NumberSignIcon />
		case 'Select':
			return <RuleIcon />
		default:
			return <TextIcon />
	}
}

