import React from "react";

const Message = props => {
  const { message, context, firstPerspectiveId } = props;
  const { messageText, user, timeStamp, isRead } = message;
  const isOwnMessage = user.id.toString() == firstPerspectiveId;
  const userName = user.name;
  const style = {
    wrapperStyle: {
      width: "100%",
      display: "flex",
      flexDirection: "column",
      marginBottom: "10px"
    },
    bubbleWrapperStyle: {
      width: "100%",
      display: "flex",
      justifyContent: isOwnMessage ? "flex-end" : "flex-start"
    },
    bubbleStyle: {
      width: "80%",
      padding: "10px",
      background: isOwnMessage ? "#dbebf9" : "#e3e3e3",
      borderRadius: "4px"
    },
    nameStyle: {
      display: "inline-block",
      width: "60%",
      textAlign: isOwnMessage ? "right" : "left",
      fontSize: "1.3rem",
      overflowX: "hidden",
      whiteSpace: "no-wrap"
    },
    readWrapperStyle: {
      textAlign: isOwnMessage ? "right" : "left"
    },
    contextStyle: {
      color: "#aaa",
      fontStyle: "italic",
      marginRight: "10px"
    }
  };

  return (
    <div style={style.wrapperStyle}>
      <div style={style.bubbleWrapperStyle}>
        <span style={style.nameStyle}>
          <span style={style.contextStyle}>{context}</span>
          <span style={{ color: "#666" }}>{isOwnMessage ? "You" : userName}</span>
          <span style={{ color: "#999" }}> {timeStamp}</span>
        </span>
      </div>
      <div style={style.bubbleWrapperStyle}>
        <div style={style.bubbleStyle}>
          <div>{messageText}</div>
        </div>
      </div>
      <div style={style.readWrapperStyle}> {isRead ? <i style={{ color: "#999" }}>read</i> : ""}</div>
    </div>
  );
};

export default Message;
