export const fetchData = (endPoint, parameters) => {
  let self = this;

  return new Promise(function (resolve, reject) {
    let xhr = new XMLHttpRequest();
    xhr.open("POST", endPoint, true);
    xhr.setRequestHeader("Content-Type", "application/json; charset=utf-8");
    xhr.onload = function () {
      if (xhr.status === 200) {
        let data = JSON.parse(xhr.responseText);
        resolve(data.result);
      } else {
        reject({
          status: this.status,
          statusText: xhr.statusText,
        });
      }
    };
    xhr.onerror = function () {
      reject({
        status: this.status,
        statusText: xhr.statusText,
      });
    };
    xhr.send(parameters);
  });
};

export const watch = (selector, callback) => {
  const el = document.querySelector(selector);
  if (el) {
    callback();
  } else {
    setTimeout(function () {
      watch(selector, callback);
    }, 200);
  }
};

export const getItemById = (array, id) => {
  return getItemByPropName(array, id.toString(), "id");
};

export const getItemByPropName = (array, propValue, propName) => {
  let current = null;
  const temp = array.filter((item) => {
    if (item[propName] && propValue) {
      return item[propName].toString() === propValue.toString();
    } else {
      return false;
    }
  });
  current = temp && temp.length > 0 ? temp[0] : null;
  return current;
};

export const getKeyByValue = (object, value) => {
  let key = Object.keys(object).find((key) => object[key] === value);
  if (!key) {
    key = value;
  }
  return key;
};

export const isEqual = (value, other) => {
  // Get the value type
  var type = Object.prototype.toString.call(value);

  // If the two objects are not the same type, return false
  if (type !== Object.prototype.toString.call(other)) return false;

  // If items are not an object or array, return false
  if (["[object Array]", "[object Object]"].indexOf(type) < 0) return false;

  // Compare the length of the length of the two items
  var valueLen =
    type === "[object Array]" ? value.length : Object.keys(value).length;
  var otherLen =
    type === "[object Array]" ? other.length : Object.keys(other).length;
  if (valueLen !== otherLen) return false;

  // Compare two items
  var compare = function (item1, item2) {
    // Get the object type
    var itemType = Object.prototype.toString.call(item1);

    // If an object or array, compare recursively
    if (["[object Array]", "[object Object]"].indexOf(itemType) >= 0) {
      if (!isEqual(item1, item2)) return false;
    }

    // Otherwise, do a simple comparison
    else {
      // If the two items are not the same type, return false
      if (itemType !== Object.prototype.toString.call(item2)) return false;

      // Else if it's a function, convert to a string and compare
      // Otherwise, just compare
      if (itemType === "[object Function]") {
        if (item1.toString() !== item2.toString()) return false;
      } else {
        if (item1 !== item2) return false;
      }
    }
  };

  // Compare properties
  if (type === "[object Array]") {
    for (var i = 0; i < valueLen; i++) {
      if (compare(value[i], other[i]) === false) return false;
    }
  } else {
    for (var key in value) {
      if (value.hasOwnProperty(key)) {
        if (compare(value[key], other[key]) === false) return false;
      }
    }
  }

  // If nothing failed, return true
  return true;
};

export const isFunction = (value) => value && typeof value === "function";
export const isNullUndefinedOrEmptyString = (val) =>
  val === null || val === undefined || val === "";

export const countDecimals = (value) => {
  if (!value || Math.floor(value) === value) return 0;
  let arr = value.toString().split(".");
  if (arr && arr.length === 2) {
    return arr[1].length;
  }
  return 0;
};

export const formatBytes = (bytes, decimals) => {
  if (bytes === 0) return "0 Bytes";
  var k = 1024,
    dm = decimals <= 0 ? 0 : decimals || 2,
    sizes = ["Bytes", "KB", "MB", "GB", "TB", "PB", "EB", "ZB", "YB"],
    i = Math.floor(Math.log(bytes) / Math.log(k));
  return parseFloat((bytes / Math.pow(k, i)).toFixed(dm)) + " " + sizes[i];
};

export const canActionOnTreeMode = ({ actionType, children }) => {
  if (children && children.length > 0) {
    for (let child of children) {
      let r = true;
      if (
        child.requireCommentActions &&
        child.requireCommentActions.includes(actionType)
      ) {
        return false;
      } else {
        r = canActionOnTreeMode({ actionType, children: child.children });
        if (!r) return false;
      }
    }
  }
  return true;
};
