import React, { Fragment } from 'react';
import { userPlus } from 'react-icons-kit/feather/userPlus';
import ContactList from './ContactList';
import IconButton from '../Base/IconButton';
import { CONTACT_PANEL_ACTIONS } from '../../Helpers/Const';

const UserControl = props => {
    return (
        <Fragment>
            <div style={{ display: 'flex' }}>{renderButtons(props)}</div>
            {props.isContactPanelOpen ? renderPanel(props) : ''}
        </Fragment>
    );
};

const renderPanel = ({ allUsers, firstPerspectiveId, currentConversation, contactPanelAction, ...rest }) => {
    const isStartNew = contactPanelAction === CONTACT_PANEL_ACTIONS.START_NEW;
    const addedUserIds = currentConversation ? currentConversation.users.map(u => u.id) : [];
    const contacts = isStartNew
        ? allUsers.filter(u => u.id !== firstPerspectiveId)
        : allUsers.filter(u => u.id !== firstPerspectiveId && addedUserIds.indexOf(u.id) < 0);
    return (
        <ContactList contacts={contacts} {...rest} firstPerspectiveId={firstPerspectiveId} isStartNew={isStartNew} />
    );
};

const renderButtons = ({ launchContactModal, currentConversationId, isSubmitterMode }) => {
    const startNewConvButton = (
        <IconButton text="Chat with" icon={userPlus} type="primary" handleClick={() => launchContactModal()} />
    );
    const addUserToConv = (
        <IconButton
            text="Add User to Chat"
            icon={userPlus}
            type="success"
            handleClick={() => launchContactModal(currentConversationId)}
        />
    );

    if (currentConversationId && !isSubmitterMode) {
        return (
            <Fragment>
                {startNewConvButton}
                {addUserToConv}
            </Fragment>
        );
    } else {
        return <Fragment>{startNewConvButton}</Fragment>;
    }
};

export default UserControl;
