import React, { Component } from 'react';
import Conversation from './Conversation';
import ConversationList from './ConversationList';
import { getItemById } from '../../Helpers/Utilities';
import IncidentList from './IncidentList';
import ContextSwitcher from './ContextSwitcher';
import UserControl from './UserControl';
import './style/intra-system-messaging.css';
import { LEVEL } from '../../Helpers/Const';

class ISMContainer extends Component {
    constructor(props) {
        super(props);
        this.state = { intervalSet: false };
        this.pull = this.pull.bind(this);
    }

    getStyle(isSubmitterMode) {
        return {
            wrapperStyle: {
                padding: '15px',
                background: '#fff',
                boxShadow: isSubmitterMode ? 'none' : '0 10px 20px rgba(0,0,0,0.19), 0 6px 6px rgba(0,0,0,0.23)',
                marginTop: isSubmitterMode ? 'none' : '25px'
            },
            leftPanelStyle: {
                height: '360px',
                overflowY: 'scroll',
                background: '#f9f9f9',
                border: '1px solid #f9f9f9'
            }
        };
    }

    componentDidMount() {
        const {
            currentIncidentNumber,
            fetchContactList,
            fetchConversationList,
            fetchIncidentList,
            isSubmitterMode,
            currentWorkItemId
        } = this.props;
        fetchContactList(currentIncidentNumber, isSubmitterMode);
        if (isSubmitterMode) {
            fetchConversationList(false, currentIncidentNumber);
        } else {
            fetchIncidentList(currentIncidentNumber, currentWorkItemId);
        }

        if (!this.state.intervalSet) {
            this.setState({ intervalSet: true });
        }
    }

    pull({ isSubmitterMode, fetchConversationList, fetchIncidentList, currentIncidentNumber, currentWorkItemId }) {
        if (isSubmitterMode) {
            fetchConversationList(true, currentIncidentNumber);
        } else {
            fetchIncidentList(currentIncidentNumber, currentWorkItemId, true, true);
        }
    }

    renderIncidentList({
        isSubmitterMode,
        incidents,
        currentIncidentId,
        selectIncident,
        firstPerspectiveId,
        isFetchingIncident
    }) {
        if (!isSubmitterMode) {
            const list = (
                <IncidentList
                    incidents={incidents}
                    currentId={currentIncidentId}
                    handleRowClick={selectIncident}
                    firstPerspectiveId={firstPerspectiveId}
                    isFetchingIncident={isFetchingIncident}
                />
            );
            return (
                <div className="row" style={{ marginBottom: '15px' }}>
                    <div className="col-md-12">{list}</div>
                </div>
            );
        }
        return null;
    }

    render() {
        const {
            incidents,
            currentIncidentId,
            currentTaskId,
            currentWorkItemId,
            currentConversationId,
            isContactPanelOpen,
            launchContactModal,
            selectConversation,
            selectTask,
            changeContext,
            firstPerspectiveId,
            isSubmitterMode,
            isSendingMessage,
            isFetchingConversations,
            markAllMessagesRead,
            selectIncident,
            isFetchingIncident,
            level,
            ...rest
        } = this.props;

        let tasks = [];
        let conversations = [];

        const currentIncident = isSubmitterMode ? null : getItemById(incidents, currentIncidentId);

        const currentTask = currentIncident ? getItemById(currentIncident.taskList, currentTaskId) : null;

        if (!isSubmitterMode) {
            if (level === LEVEL.CASE) {
                conversations = currentIncident
                    ? currentIncident.conversations.map(c => ({
                          ...c,
                          context: currentIncident.incidentNumber
                      }))
                    : [];
            } else if (level === LEVEL.TASK) {
                if (currentTaskId && currentTaskId.toString() !== '0') {
                    conversations = currentIncident
                        ? currentTask
                            ? currentTask.conversations.map(c => ({
                                  ...c,
                                  context: `${currentIncident.incidentNumber} ${currentTask.name}`
                              }))
                            : []
                        : [];
                }
            }
            tasks = currentIncident ? currentIncident.taskList : [];
        } else {
            conversations = this.props.conversations;
        }

        const currentConversation = getItemById(conversations, currentConversationId);

        const style = this.getStyle(isSubmitterMode);

        return (
            <div style={style.wrapperStyle}>
                <div className="ism-container">
                    {this.renderIncidentList(this.props)}
                    <div className="row">
                        {isSubmitterMode ? null : (
                            <div className="col-sm-12">
                                <ContextSwitcher
                                    level={level}
                                    tasks={tasks}
                                    currentTaskId={currentTaskId}
                                    selectTask={selectTask}
                                    changeContext={changeContext}
                                />
                            </div>
                        )}
                        <div className="col-sm-4" style={{ paddingRight: '0' }}>
                            <UserControl {...this.props} currentConversation={currentConversation} />
                            <div style={style.leftPanelStyle}>
                                <ConversationList
                                    currentConversationId={currentConversationId}
                                    conversations={conversations}
                                    selectConversation={selectConversation}
                                    firstPerspectiveId={firstPerspectiveId}
                                    isFetchingConversations={isFetchingConversations}
                                />
                            </div>
                        </div>
                        <div className="col-sm-8">
                            {!currentConversation ? (
                                ''
                            ) : (
                                <Conversation
                                    markAllMessagesRead={markAllMessagesRead}
                                    conversation={currentConversation}
                                    firstPerspectiveId={firstPerspectiveId}
                                    currentIncidentId={currentIncidentId}
                                    currentWorkItemId={currentWorkItemId}
                                    {...rest}
                                />
                            )}
                        </div>
                    </div>
                </div>
            </div>
        );
    }
}

export default ISMContainer;
