import React from 'react';
import { createRoot } from 'react-dom/client';
import { unmountComponentAtNode } from 'react-dom';
import { Provider, connect } from 'react-redux';
import { createStore, applyMiddleware } from 'redux';
import { thunk } from 'redux-thunk';

import ISMContainer from './ISMContainer';
import intraSystemMessageReducer from '../../Reducers/intraSystemMessageReducer';
import {
    SET_MODE,
    FETCH_CONTACT_LIST,
    FETCH_INCIDENT_LIST,
    FETCH_CONVERSATION_LIST,
    ADD_USERS_TO_CONVERSATION,
    CREATE_MESSAGE,
    MARK_ALL_MESSAGES_READ,
    CREATE_CONVERSATION
} from '../../Helpers/Const';
import { ISMconfig } from '../../config';
import {
    launchContactModal,
    closeModal,
    startAsyncFunction,
    fetchConversationListThunk,
    fetchContactListThunk,
    fetchIncidentListThunk,
    initializeConversationThunk,
    initializeMessageThunk,
    addUserToConversationThunk,
    markAllMessagesReadThunk,
    selectConversation,
    selectTask,
    selectIncident,
    changeContext,
    autoSaveUnsendMessage
} from '../../Helpers/IntraSystemMessageActions';

const store = createStore(intraSystemMessageReducer, applyMiddleware(thunk));

const mapStateToProps = state => {
    return {
        // Only return the specific properties that the component actually uses
        incidents: state.incidents,
        currentIncidentId: state.currentIncidentId,
        currentTaskId: state.currentTaskId,
        currentWorkItemId: state.currentWorkItemId,
        currentConversationId: state.currentConversationId,
        isContactPanelOpen: state.isContactPanelOpen,
        selectConversation: state.selectConversation,
        selectTask: state.selectTask,
        changeContext: state.changeContext,
        firstPerspectiveId: state.firstPerspectiveId,
        isSubmitterMode: state.isSubmitterMode,
        isSendingMessage: state.isSendingMessage,
        isFetchingConversations: state.isFetchingConversations,
        markAllMessagesRead: state.markAllMessagesRead,
        selectIncident: state.selectIncident,
        isFetchingIncident: state.isFetchingIncident,
        level: state.level,
        conversations: state.conversations,
        allUsers: state.allUsers,
        currentIncidentNumber: state.currentIncidentNumber,
        alertMessage: state.alertMessage,
        contactPanelAction: state.contactPanelAction
    };
};

const mapDispatchToProps = (dispatch, ownProps) => {
    return {
        /* If a conversationId is provided, the panel launched
		will be a 'add users' panel, otherwise a 'start new' panel */
        launchContactModal: (currentConversationId /*optional*/) => {
            dispatch(launchContactModal(currentConversationId));
        },

        collapseList: () => {
            dispatch(closeModal());
        },

        selectIncident: incidentId => {
            dispatch(fetchContactListThunk(ISMconfig.endPoints[FETCH_CONTACT_LIST], incidentId, false, selectIncident));
        },

        selectTask: taskId => {
            dispatch(selectTask(taskId));
        },

        selectConversation: conversationId => {
            dispatch(selectConversation(conversationId));
        },

        changeContext: context => {
            dispatch(changeContext(context));
        },

        autoSaveUnsendMessage: unsendMessage => {
            dispatch(autoSaveUnsendMessage(unsendMessage));
        },

        addUserToConversation: (userIdList, currentConversationId, currentIncidentId) => {
            dispatch(
                addUserToConversationThunk(
                    ISMconfig.endPoints[ADD_USERS_TO_CONVERSATION],
                    userIdList,
                    currentConversationId,
                    currentIncidentId
                )
            );
        },
        sendMessage: (text, conversationId, workItemId) => {
            dispatch(initializeMessageThunk(ISMconfig.endPoints[CREATE_MESSAGE], text, conversationId, workItemId));
        },

        initializeConversation: (
            userIdList,
            incidentId /*optional*/,
            taskId /*optional*/,
            workItemId /*optional*/,
            mode
        ) => {
            dispatch(
                initializeConversationThunk(
                    ISMconfig.endPoints[CREATE_CONVERSATION],
                    userIdList,
                    incidentId,
                    taskId,
                    workItemId,
                    mode
                )
            );
        },

        // KeepCurrentState flag used when you want the fetching process to work in background
        // and not be noticeable to end user except for updating message thread
        fetchConversationList: (keepCurrentState, incidentNumber /*optional*/) => {
            if (!keepCurrentState) {
                dispatch(startAsyncFunction(FETCH_CONVERSATION_LIST));
            }
            dispatch(fetchConversationListThunk(ISMconfig.endPoints[FETCH_CONVERSATION_LIST], incidentNumber));
        },

        fetchContactList: (incidentNumber, isSubmitterMode) => {
            dispatch(fetchContactListThunk(ISMconfig.endPoints[FETCH_CONTACT_LIST], incidentNumber, isSubmitterMode));
        },

        fetchIncidentList: (currentIncidentNumber, currentWorkItemId, keepCurrentState, fromAutoSync) => {
            if (!keepCurrentState) {
                dispatch(startAsyncFunction(FETCH_INCIDENT_LIST));
            }
            dispatch(
                fetchIncidentListThunk(
                    ISMconfig.endPoints[FETCH_INCIDENT_LIST],
                    currentWorkItemId,
                    currentIncidentNumber,
                    keepCurrentState,
                    ownProps,
                    fromAutoSync
                )
            );
        },

        markAllMessagesRead: (conversationId, currentIncidentId) => {
            dispatch(
                markAllMessagesReadThunk(ISMconfig.endPoints[MARK_ALL_MESSAGES_READ], conversationId, currentIncidentId)
            );
        }
    };
};

const ISMRoot = connect(
    mapStateToProps,
    mapDispatchToProps
)(ISMContainer);

const initializeMessaging = (mode, mountId, type, incidentNumber, workItemId, taskId) => {
    const rootEl = document.getElementById(mountId);
    unmountComponentAtNode(rootEl);

    store.dispatch({ type: SET_MODE, payload: { mode, incidentNumber, workItemId } });

    const root = createRoot(rootEl);
    root.render(
        <Provider store={store}>
            <ISMRoot incidentNumber={incidentNumber} taskId={taskId} type={type} />
        </Provider>
    );
};

export default initializeMessaging;
