import axios from "axios";
import { fetchData, getKeyByValue } from "./Utilities";
import { parseGroup } from "./FilterHelper";
import { runtimeFilterConfig } from "../config";
import {
  UPDATE_NAME,
  VALIDATE_FILTER_GROUP_NAME,
  ADD_TO_FILTER,
  ADD_FILTER,
  SELECT_FILTER,
  REMOVE_FILTER_FIELD,
  UPDATE_FILTER_FIELD,
  UPDATE_RULE,
  UPDATE_FILTER_LOGIC,
  REMOVE_FILTER,
  FETCH_FIELDS,
  FETCH_FILTERS,
  FETCH_FIELDS_LIST,
  UPDATE_RUNTTIME_LIST,
  START_FETCH_FIELDS,
  CLEAR_LOADING,
  START_LOADING,
  CLEAR_MESSAGE,
  LOG_ERROR,
  FILTER_DEPENDENCY_TYPE,
  UPDATE_DEPENDENCY,
  FILTER_TYPES,
  RESET,
  INVALID_RUNTIME_FILTER,
  FETCH_FORM_AND_TASK_FIELDS,
  SET_LOADING_FORM_AND_TASK_FIELDS,
  SUPPLEMENT_FIELDS,
} from "./Const";

let baseUrl = location.origin;

if (location.href.indexOf("/WorkflowAssignment") > 0) {
  baseUrl = location.href.substring(
    0,
    location.href.lastIndexOf("/WorkflowAssignment")
  );
}

export const updateFilterGroupName = function (name) {
  return { type: UPDATE_NAME, payload: { name } };
};

export const validateFilterGroupName = ({ valid, message }) => {
  return { type: VALIDATE_FILTER_GROUP_NAME, payload: { valid, message } };
};

export const addToFilter = function (field, filterId) {
  return { type: ADD_TO_FILTER, payload: { field, filterId: filterId } };
};

export const addFilter = function (logic, readOnly) {
  return { type: ADD_FILTER, payload: { logic, readOnly } };
};

export const selectFilter = function (id) {
  return { type: SELECT_FILTER, payload: { id } };
};

export const removeFilterField = function (filterId, fieldId, fieldName) {
  return { type: REMOVE_FILTER_FIELD, payload: { filterId, fieldId } };
};

// used in filter editor
export const updateField = function (
  filterId,
  fieldId,
  entry,
  value,
  fieldName
) {
  if (fieldName === FILTER_DEPENDENCY_TYPE.FORM_NAME && entry === "value") {
    return updateFieldThunk(
      filterId,
      fieldId,
      entry,
      value,
      fieldName,
      "WorkItemFilterGroup"
    );
  } else {
    return {
      type: UPDATE_FILTER_FIELD,
      payload: { filterId, fieldId, entry, value },
    };
  }
};

export const updateDependency = function (dependencyType, dependencyId) {
  return { type: UPDATE_DEPENDENCY, payload: { dependencyType, dependencyId } };
};

// used in runtime filter prmpt
export const updateRule = function (value, ruleId, type) {
  return { type: UPDATE_RULE, payload: { value, ruleId, type } };
};

export const updateFilterLogic = function (filterId, filterLogic) {
  return { type: UPDATE_FILTER_LOGIC, payload: { filterId, filterLogic } };
};

export const removeFilter = function (filterIndex) {
  return { type: REMOVE_FILTER, payload: { filterIndex } };
};

export const fetchFields = function ({ fields, noReport, config }) {
  return { type: FETCH_FIELDS, payload: { fields, noReport, config } };
};

export const fetchFilters = function (group) {
  // Handle case where group is undefined or null
  if (!group) {
    return {
      type: FETCH_FILTERS,
      payload: { group: null, formId: null },
    };
  }
  
  return {
    type: FETCH_FILTERS,
    payload: { group: parseGroup(group), formId: group.FormId || null },
  };
};

export const clearMessage = function () {
  return { type: CLEAR_MESSAGE };
};

export const clearReduxState = function () {
  return { type: RESET };
};

export const clearLoading = function () {
  return { type: CLEAR_LOADING };
};

export const startLoading = function () {
  return { type: START_LOADING };
};

export const supplementFields = (newFields) => {
  return { type: SUPPLEMENT_FIELDS, payload: newFields };
};

export const submitRuntimeFilter = function (filterGroupId, filterType) {
  return function (dispatch, getState) {
    let invalidRules = [];
    let filters = getState().filterEditor.filters;

    filters.forEach((f) => {
      f.Nodes.forEach((node) => {
        if (node && node.Rule && node.Rule.ValueOptions) {
          if (
            node.Rule.IsRequired &&
            (node.Rule.Value === "0" || node.Rule.Value === "")
          ) {
            invalidRules.push(node.Rule);
          }
          node.Rule.Value =
            getKeyByValue(node.Rule.ValueOptions, node.Rule.Value) ||
            node.Rule.Value;
        }
      });
    });

    if (invalidRules.length > 0) {
      return {
        type: INVALID_RUNTIME_FILTER,
        payload: { invalidRules },
      };
    } else {
      dispatch(startLoading());
      return axios
        .post(baseUrl + runtimeFilterConfig.endPoints[UPDATE_RUNTTIME_LIST], {
          filtersJson: JSON.stringify(filters),
          filterGroupId,
          filterType,
        })
        .then(
          (result) => {
            const $ = window.jQuery;
            const tbl = document.getElementById(filterGroupId);
            const html = $(result.data.list).html();
            tbl.innerHTML = html;

            const $tab = $("div[data-id=" + filterGroupId + "]");
            const $count = $tab.find(".badge-circle");
            if ($count && $count.length > 0) {
              $count[0].innerHTML = result.data.count;
            }

            Array.from(tbl.getElementsByTagName("th")).forEach((ele) => {
              attachEventListenerToColumn(ele);
            });
            addEventListenerToAppendedView($);

            dispatch(clearMessage());
            dispatch(clearLoading());
            $(".data-table-" + filterGroupId).DataTable({
              bDestroy: true,
              bFilter: true,
              deferRender: true,
              aaSorting: buildSortRule(tbl, result.data.sort),
            });
          },
          (error) => dispatch(logError(error))
        );
    }
  };
};

const addEventListenerToAppendedView = ($) => {
  const $viewControl = $(".view-control");
  const $views = $(".work-item-group");
  $viewControl.on("click", function (e) {
    $views.hide();
    $viewControl.removeClass("active").addClass("inactive");
    $(this).addClass("active").removeClass("inactive");
    $("#" + this.dataset.show + "_tab").show();
  });
};

const buildSortRule = (tbl, sortSetting) => {
  let sortRule = [];
  const fSort = sortSetting;
  if (fSort) {
    Array.from(tbl.getElementsByTagName("th")).forEach(function (ele, index) {
      applySortPreference(ele, index, fSort, sortRule);
    });
  }
  return sortRule;
};

const applySortPreference = (ele, index, fSort, sortRule) => {
  const col = ele.innerText;
  const array = fSort.split("$__$");
  if (array.length === 2) {
    const colName = array[0];
    const order = array[1];
    if (order && colName.trim() === col.trim()) {
      if (order.includes("asc")) {
        sortRule.push([index, "asc"]);
      } else if (order.includes("desc")) {
        sortRule.push([index, "desc"]);
      }
    }
  }
};

const attachEventListenerToColumn = (ele) => {
  window.jQuery(ele).on("click", () => {
    setTimeout(() => {
      const id = window.jQuery(ele).closest(".case-tab").attr("id");
      const allGroups = [];
      window.jQuery(".case-tab").each(function (index, tab) {
        allGroups.push(window.jQuery(tab).attr("id"));
      });
      $.ajax({
        url: app.fixUrl("/User/SaveColumnSort"),
        data: {
          column: ele.innerText,
          sort: ele.classList[0],
          filterGroupId: id,
          allGroups,
        },
        method: "POST",
      });
    }, 200);
  });
};

export const logError = (error) => {
  return { type: LOG_ERROR, payload: { error } };
};

// # async functions #
export const saveFilterGroupThunk = (endpoint, filterGroup, type) => {
  return function (dispatch) {
    return axios
      .post(baseUrl + endpoint, {
        filterJson: JSON.stringify(filterGroup),
        type,
      })
      .then(
        (result) => {
          const { id } = result.data;
          sessionStorage.setItem("selectedFilterGroupId", id);
          location.reload();
        },
        (error) => dispatch(logError(error))
      );
  };
};

export const deleteFilterGroupThunk = (filterGroupId, endpoint) => {
  return function (dispatch) {
    return axios
      .post(baseUrl + endpoint, {
        filterGroupId: JSON.stringify(filterGroupId),
      })
      .then(
        (result) => {
          if (result) location.reload();
        },
        (error) => dispatch(logError(error))
      );
  };
};

const myPromiseFunc = (data) => {
    return new Promise((resolve, reject) => {
        if (data) {
            resolve(data);
        } else {
            reject("It broke");
        }
    });
};

let fieldsListCount = 0;

export const fetchFieldsListThunk = (
  endpoint,
  type /*optional*/,
  dependencyType /*optional*/,
  dependencyId /*optional*/
) => {
  return function (dispatch) {
    dispatch({
      type: START_FETCH_FIELDS,
      payload: { dependencyType, dependencyId },
    });

      fieldsListCount++;

      var fieldsListJson = { type: type, dependencyType: dependencyType, dependencyId: dependencyId };
      var fieldsListParamData = JSON.parse(window.localStorage.getItem('fieldsListParam'));
      var isFieldsListParamValid = fieldsListParamData && fieldsListParamData.type == type && fieldsListParamData.dependencyType == dependencyType && fieldsListParamData.dependencyId == dependencyId;
      if (!fieldsListParamData || !isFieldsListParamValid) {
          window.localStorage.setItem('fieldsListParam', JSON.stringify(fieldsListJson));
      }
      
      if (fieldsListCount == 1 || !isFieldsListParamValid) {
          window.fieldsListData = null;

          return axios.post(
              baseUrl + endpoint, fieldsListJson
            ).then(
                (result) => {
                    
                if (result.status != 200) {
                    // do something here
                    return;
                    }
                    window.fieldsListData = JSON.stringify(result.data.result);
                    dispatch(fetchFields(result.data.result));

                    $(".available-field-div").hide();
                    $("div[formid|='0']").show();
                    if (dependencyId > 0) {
                        $("div[formid|='" + dependencyId + "']").show();
                    }
              },
              (error) => dispatch(logError(error))
          );
      } else {
          // sleep till above if api response
          const checkInterval = setInterval(() => {
              const fieldsListData = window.fieldsListData;
              
              if (fieldsListData != null) {
                  clearInterval(checkInterval);
                  
                  return myPromiseFunc(fieldsListData).then(
                      (result) => {
                          dispatch(fetchFields(JSON.parse(result)));

                          $(".available-field-div").hide();
                          $("div[formid|='0']").show();
                          if (dependencyId > 0) {
                              $("div[formid|='" + dependencyId + "']").show();
                          }
                      },
                      (error) => dispatch(logError(error))
                  ).finally(() => {
                  });
              }
          }, 3000); // Check every three second
      }
  };
};

export const fetchFilterGroupsThunk = (endpoint, filterGroupId, type) => {
  return function (dispatch) {
    // Ensure filterGroupId is properly converted to string for API
    const effectiveFilterGroupId = filterGroupId !== undefined && filterGroupId !== null 
      ? String(filterGroupId) 
      : null;
    
    return fetchData(
      baseUrl + endpoint,
      JSON.stringify({ filterGroupId: effectiveFilterGroupId, type })
    ).then(
      (result) => {
        let rule = null;
        //if any of the rule is a form name rule, we will need to fetch available fields for this form name
        if (result && result.Filters) {
          result.Filters.forEach((f) => {
            f.Nodes.forEach((n) => {
              if (
                n.Rule &&
                n.Rule.FieldName === FILTER_DEPENDENCY_TYPE.FORM_NAME
              ) {
                rule = n.Rule;
              }
            });
          });
          if (rule) {
            dispatch(
              fetchFieldsListThunk(
                "/Filter/FetchFieldsList",
                type,
                getKeyByValue(rule.ValueOptions, rule.Value)
              )
            );
          }
        }
        dispatch(fetchFilters(result));
      },
      (error) => dispatch(logError(error))
    );
  };
};

export const validateFilterGroupNameThunk = (
  endpoint,
  name,
  filterGroupId,
  type
) => {
  return (dispatch) => {
    return fetchData(
      baseUrl + endpoint,
      JSON.stringify({ name, filterGroupId, type })
    )
      .then(
        (result) => {
          dispatch(validateFilterGroupName(result));
        },
        (error) => dispatch(logError(error))
      );
    // Note: updateFilterGroupName is already dispatched immediately in FilterEditorRoot.jsx
    // before this thunk is called. Dispatching it again here after async validation
    // causes a race condition where typed characters are lost.
  };
};

let formTaskFieldCount = 0;

export const fetchFormAndTaskFieldsThunk = (
  endpoint,
  workflowDefinitionId,
  workflowTaskDefinitionId,
  workflowDefinitionType
) => {
    return function (dispatch) {
        dispatch({ type: SET_LOADING_FORM_AND_TASK_FIELDS, payload: true });

        formTaskFieldCount++;

        if (formTaskFieldCount == 1) {
            window.formAndTaskFieldsData = null;
        return axios
            .get(
                `${baseUrl}${endpoint}?workflowDefinitionId=${workflowDefinitionId}&workflowTaskDefinitionId=${workflowTaskDefinitionId}&workflowDefinitionType=${workflowDefinitionType}`
            )
            .then(
                (result) => {
                    if (!result.data.success) {
                        // do something here
                        return;
                    }
                    
                    window.formAndTaskFieldsData = JSON.stringify(result.data);

                    dispatch({
                        type: FETCH_FORM_AND_TASK_FIELDS,
                        payload: result.data.data,
                    });
                },
                (error) => dispatch(logError(error))
            )
            .finally(() =>
                dispatch({ type: SET_LOADING_FORM_AND_TASK_FIELDS, payload: false })
            );
        } else {
            // sleep till above if api response
            const checkIntervalFetchFormTaskField = setInterval(() => {
                const formTaskFieldData = window.formAndTaskFieldsData;
                
                if (formTaskFieldData) {
                    clearInterval(checkIntervalFetchFormTaskField);
                    
                    return myPromiseFunc(formTaskFieldData).then(
                        (result) => {
                            dispatch({
                                type: FETCH_FORM_AND_TASK_FIELDS,
                                payload: JSON.parse(result).data
                            });
                        },
                        (error) => dispatch(logError(error))
                    )
                        .finally(() => {
                            dispatch({ type: SET_LOADING_FORM_AND_TASK_FIELDS, payload: false });
                        });
                }
            }, 3000); // Check every three second
        }
    };
};

const updateFieldThunk = (
  filterId,
  fieldId,
  entry,
  fieldValue,
  fieldName,
  type
) => {
  return (dispatch) => {
    return fetchData(
      baseUrl + "/Filter/GetResponseContainerId",
      JSON.stringify({ fieldName, fieldValue })
    )
      .then(
        () => {
          dispatch(fetchFieldsListThunk("/Filter/FetchFieldsList", type));
        },
        (error) => dispatch(logError(error))
      )
      .then(() => {
        dispatch(updateField(filterId, fieldId, entry, fieldValue));
      });
  };
};

// # end of async functions #

export const getFilterCommonFunctions = (dispatch) => {
  return {
    updateField: (filterId, fieldId, entry, value, fieldName) => {
      dispatch(updateField(filterId, fieldId, entry, value, fieldName));
    },

    updateFilterLogic: (fitlerId, logic) => {
      dispatch(updateFilterLogic(fitlerId, logic));
    },

    addToFilter: (field, filterId) => {
      dispatch(addToFilter(field, filterId));
    },

    addFilter: (
      logic /*optional [and][or]*/,
      readOnly /*optional [true][false]*/
    ) => {
      dispatch(addFilter(logic, readOnly));
    },

    selectFilter: (filterId) => {
      dispatch(selectFilter(filterId));
    },

    removeFilterField: (filterId, fieldId, fieldName) => {
      dispatch(removeFilterField(filterId, fieldId, fieldName));
    },

    removeFilter: (filterIndex) => {
      dispatch(removeFilter(filterIndex));
    },
  };
};
