import {
    SET_MODE,
    ISM_MODE,
    SET_CURRENT_USER,
    START_SEND_MESSAGE,
    FINISH_SEND_MESSAGE,
    ERROR_SEND_MESSAGE,
    LAUNCH_CONTACT_MODAL,
    CLOSE_MODAL,
    SELECT_CONVERSATION,
    SELECT_INCIDENT,
    SELECT_TASK,
    CHANGE_CONTEXT,
    START_FETCH_CONVERSATION,
    START_FETCH_INCIDENT,
    FETCH_CONVERSATION_LIST,
    FETCH_CONTACT_LIST,
    END_FETCH_INCIDENTS,
    LOADING,
    FINISH_CREATE_CONVERSATION,
    FINISH_ADD_USER_TO_CONVERSATION,
    ERROR_CREATE_CONVERSATION,
    MARK_ALL_MESSAGES_READ,
    LEVEL,
    CONTACT_PANEL_ACTIONS
} from '../Helpers/Const';

const defaultState = {
    currentConversationId: '',
    currentIncidentId: '',
    currentWorkItemId: '',
    currentTaskId: '', //let empty if level is case level
    currentIncidentNumber: '',
    level: LEVEL.CASE, //Case or Task
    firstPerspectiveId: '', //load on init
    incidents: [], //only used in inverstigator view
    allUsers: [], //load on init, list of users
    conversations: [], // load on init
    alertMessage: '',
    contactPanelAction: CONTACT_PANEL_ACTIONS.START_NEW,
    isContactPanelOpen: false,
    isFetchingConversations: false,
    isFetchingIncident: false,
    isSendingMessage: false,
    isSubmitterMode: true
};

const intraSystemMessageReducer = (state = defaultState, action) => {
    const { type, payload } = action;
    let currentUser = null;

    let conversationList = state.conversations.slice();
    let newConversationList = [];
    let incidentList = state.incidents.slice();
    let newIncidentList = [];

    if (!currentUser && state.allUsers && state.firstPerspectiveId) {
        currentUser = state.allUsers.filter(user => user.id.toString() == state.firstPerspectiveId)[0];
    }

    switch (type) {
        case FETCH_CONVERSATION_LIST:
            return {
                ...state,
                conversations: payload.conversations ? payload.conversations : [],
                isFetchingConversations: false
            };

        case START_FETCH_CONVERSATION:
            return { ...state, isFetchingConversations: true };

        case FETCH_CONTACT_LIST:
            const { allUsers, currentUserId } = payload;
            return {
                ...state,
                allUsers: allUsers,
                firstPerspectiveId: currentUserId
            };

        case START_FETCH_INCIDENT:
            return { ...state, isFetchingIncident: true };

        case END_FETCH_INCIDENTS:
            return {
                ...state,
                isFetchingIncident: false,
                incidents: payload.hasNewMessage ? payload.incidents : incidentList
            };

        case SET_CURRENT_USER:
            return { ...state, firstPerspectiveId: payload.id };

        case LAUNCH_CONTACT_MODAL:
            return {
                ...state,
                isContactPanelOpen: true,
                contactPanelAction: payload.conversationId
                    ? CONTACT_PANEL_ACTIONS.ADD_USERS
                    : CONTACT_PANEL_ACTIONS.START_NEW
            };

        case CHANGE_CONTEXT:
            return {
                ...state,
                level: payload.context,
                currentConversationId: '',
                currentTaskId: ''
            };

        case SET_MODE:
            const { incidentNumber, mode, workItemId } = payload;
            return {
                ...state,
                isSubmitterMode: mode === ISM_MODE.SUBMITTER,
                currentIncidentNumber: incidentNumber,
                currentWorkItemId: workItemId
            };

        case CLOSE_MODAL:
            return { ...state, isContactPanelOpen: false };

        case SELECT_CONVERSATION:
            const { conversationId } = payload;
            return { ...state, currentConversationId: conversationId };

        case SELECT_TASK:
            return {
                ...state,
                level: LEVEL.TASK,
                currentTaskId: payload.taskId
            };

        case SELECT_INCIDENT:
            const selectedIncident = incidentList.filter(inc => inc.id == payload.incidentId)[0];
            const newState = {
                ...state,
                level: LEVEL.CASE,
                currentWorkItemId: parseInt(payload.workItemId) > 0 ? payload.workItemId : selectedIncident.workItemId,
                currentConversationId: '',
                currentIncidentId: selectedIncident ? selectedIncident.id : '',
                currentIncidentNumber: selectedIncident ? selectedIncident.incidentNumber : ''
            };

            if (selectedIncident && !state.isSubmitterMode) {
                const tasksHasConversation = selectedIncident.taskList.filter(t => t.conversations.length > 0);

                //If selected incident has no case-level conversation but has task-level conversation,
                //show first task level conversation
                if (tasksHasConversation.length > 0 && selectedIncident.conversations.length == 0) {
                    return {
                        ...newState,
                        level: LEVEL.TASK,
                        currentTaskId: tasksHasConversation[0].id,
                        currentConversationId: tasksHasConversation[0].conversations[0].id
                    };
                } else {
                    return newState;
                }
            } else {
                return newState;
            }

        case MARK_ALL_MESSAGES_READ:
        case FINISH_ADD_USER_TO_CONVERSATION:
        case FINISH_CREATE_CONVERSATION:
        case FINISH_SEND_MESSAGE:
            const { conversation } = payload;
            const { relateId, level } = conversation;

            if (!state.isSubmitterMode) {
                //investigator mode
                newIncidentList = incidentList.map(inc => {
                    if (level === LEVEL.CASE) {
                        if (inc.id.toString() == relateId.toString()) {
                            let newIncConversations = inc.conversations;
                            //conversation is newly added
                            if (inc.conversations.filter(c => c.id == conversation.id).length == 0) {
                                newIncConversations.push(conversation);
                            } else {
                                // update existing conversation
                                newIncConversations = inc.conversations.slice().map(c => {
                                    if (c.id == conversation.id) {
                                        return conversation;
                                    } else {
                                        return c;
                                    }
                                });
                            }
                            return { ...inc, conversations: newIncConversations };
                        } else {
                            return inc;
                        }
                    } else if (level === LEVEL.TASK) {
                        if (inc.id == state.currentIncidentId) {
                            const newTaskList = inc.taskList.map(t => {
                                if (t.id == relateId) {
                                    let newTaskConversations = t.conversations;
                                    //conversation is newly added
                                    if (t.conversations.filter(c => c.id == conversation.id).length == 0) {
                                        newTaskConversations.push(conversation);
                                    } else {
                                        // update existing conversation
                                        newTaskConversations = t.conversations.map(c => {
                                            return c.id == conversation.id ? conversation : c;
                                        });
                                    }
                                    return {
                                        ...t,
                                        conversations: newTaskConversations
                                    };
                                } else {
                                    return t;
                                }
                            });
                            return {
                                ...inc,
                                taskList: newTaskList
                            };
                        } else {
                            return inc;
                        }
                    }
                });
                return {
                    ...state,
                    isSendingMessage: false,
                    incidents: newIncidentList,
                    currentConversationId: conversation.id,
                    isContactPanelOpen: false,
                    isFetchingIncident: false
                };
            } else {
                //submitter mode
                let isNew = true;
                newConversationList = conversationList.map(conv => {
                    if (conv.id == conversation.id) {
                        isNew = false;
                        conversation.firstPerspectiveId = state.firstPerspectiveId;
                        return conversation;
                    } else {
                        return conv;
                    }
                });
                if (isNew) {
                    newConversationList.push(conversation);
                }
                return {
                    ...state,
                    isSendingMessage: false,
                    conversations: newConversationList,
                    currentConversationId: conversation.id,
                    isContactPanelOpen: false
                };
            }

        case ERROR_CREATE_CONVERSATION:
        case ERROR_SEND_MESSAGE:
            return {
                ...state,
                isSendingMessage: false,
                alertMessage: 'Error occurred'
            };

        default:
            return { ...state };
    }
};

export default intraSystemMessageReducer;
