import React, { useMemo } from 'react';
import { useTable } from 'react-table';
import SpinnerPlaceholder from '../Base/SpinnerPlaceholder';

function IncidentList({ incidents, isFetchingIncident, currentId, handleRowClick, firstPerspectiveId }) {
  const data = useMemo(() => incidents || [], [incidents]);

  // Helper to count unread messages
  const countUreadMessage = (conversation) => {
    if (conversation && conversation.messages) {
      return conversation.messages.filter(
        msg => !msg.isRead && msg.user.id.toString() !== firstPerspectiveId
      ).length;
    }
    return 0;
  };

  // Custom cell renderer for Workflow Id
  const renderWorkflowIdCell = ({ row, value }) => {
    const unreadIncidentLevelMsgCount = row.original.conversations
      .map(cvs => countUreadMessage(cvs))
      .reduce((acc, val) => acc + parseInt(val), 0);
    const unreadTaskLevelMsgCount = []
      .concat(
        row.original.taskList
          .filter(task => task.conversations.length > 0)
          .map(task => task.conversations.map(cvs => countUreadMessage(cvs)))
      )
      .reduce((acc, val) => acc + parseInt(val), 0);
    const unreadTotal = parseInt(unreadIncidentLevelMsgCount) + parseInt(unreadTaskLevelMsgCount);
    if (unreadTotal > 0) {
      return (
        <div>
          <span>{value}</span>
          <span className="badge" style={{ float: 'right', marginRight: '10px' }}>
            {unreadTotal}
          </span>
        </div>
      );
    }
    return value;
  };

  const columns = useMemo(() => [
    {
      Header: 'Workflow Id',
      accessor: 'incidentNumber',
      Cell: renderWorkflowIdCell,
      minWidth: 170
    },
    { Header: 'Category', accessor: 'category' },
    { Header: 'Sub Category', accessor: 'subCategory' },
    { Header: 'Status', accessor: 'status' },
    { Header: 'Reported', accessor: 'reported' },
    { Header: 'Due Date', accessor: 'dueDate' }
  ], []);

  const {
    getTableProps,
    getTableBodyProps,
    headerGroups,
    rows,
    prepareRow
  } = useTable({ columns, data });

  if (isFetchingIncident && (!incidents || incidents.length === 0)) {
    return <SpinnerPlaceholder name="ball-clip-rotate" height="180px" color="#4c9be3" />;
  }

  return (
    <table {...getTableProps()} style={{ width: '100%', height: '180px' }} className="-striped -highlight">
      <thead>
        {headerGroups.map(headerGroup => (
          <tr {...headerGroup.getHeaderGroupProps()}>
            {headerGroup.headers.map(column => (
              <th {...column.getHeaderProps()}>{column.render('Header')}</th>
            ))}
          </tr>
        ))}
      </thead>
      <tbody {...getTableBodyProps()}>
        {rows.map(row => {
          prepareRow(row);
          const isCurrent = row.original.id && row.original.id.toString() === (currentId || '').toString();
          return (
            <tr
              {...row.getRowProps()}
              style={{ backgroundColor: isCurrent ? '#dbebf9' : 'white', cursor: 'pointer' }}
              onClick={() => handleRowClick && handleRowClick(row.original.id)}
            >
              {row.cells.map(cell => (
                <td {...cell.getCellProps()}>{cell.render('Cell')}</td>
              ))}
            </tr>
          );
        })}
      </tbody>
    </table>
  );
}

export default IncidentList;
