import React from 'react';

const ConversationListItem = props => {
    const { id, users, isCurrent, unreadCount, handleClick, firstPerspectiveId } = props;
    const style = {
        height: '62px',
        cursor: 'pointer',
        overflowY: 'hidden'
    };
    const pillStyle = {
        marginRight: '5px',
        marginBottom: '5px',
        borderRadius: '15px',
        display: 'inline-flex',
        backgroundColor: 'white'
    };
    const className = isCurrent ? 'list-group-item active' : 'list-group-item';
    const usernamePills = users
        .filter(user => user.id.toString() !== firstPerspectiveId)
        .map(user => (user.isAnonymous ? 'Anonymous' : user.name))
        .map(username => (
            <button type="button" className="btn btn-sm" key={username} style={pillStyle}>
                {username}
            </button>
        ));

    return (
        <div className={className} style={style} onClick={() => handleClick(id)}>
            {unreadCount > 0 ? <span className="badge">{unreadCount}</span> : ''}
            {usernamePills}
        </div>
    );
};

export default ConversationListItem;
